ValidationRule.errorConditionFormula:
IF(
    /* Applicant is under 18 */
    ( TODAY() - Date_of_Birth__c ) / 365 < 18,

    /* Then: POA fields must be filled AND POA must be adult */
    OR(
        ISBLANK(Power_of_Attorney__c),
        ISBLANK(Power_of_Attorney_DOB__c),
        ( TODAY() - Power_of_Attorney_DOB__c ) / 365 < 18
    ),

    /* If applicant is 18+ → no error */
    FALSE
)
